def levenshtein(a: String, b: String) -> Int:
    var n = a.byte_length()
    var m = b.byte_length()
    var prev = InlineArray[Int](fill=0, length=m + 1)
    var cur = InlineArray[Int](fill=0, length=m + 1)
    for i in range(1, n + 1):
        cur[0] = i
        for j in range(1, m + 1):
            var cost = 0
            if a[byte(i - 1)] == b[byte(j - 1)]:
                cost = 0
            else:
                cost = 1
            cur[j] = min(prev[j] + 1, cur[j - 1] + 1, prev[j - 1] + cost)
        var t = prev^
        prev[:] = cur^
        cur[:] = t^
    return prev[m]

def run_length_encode(s: String) -> String:
    var n = s.byte_length()
